'use client';

import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { useAlert } from '@/lib/use-alert';
import jsPDF from 'jspdf';
import {
  BookOpen,
  Building2,
  Calendar,
  CalendarDays,
  Download,
  GraduationCap,
  Hash,
  Layers,
  User2,
} from 'lucide-react';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { useStudentAuth } from '../hooks/useStudentAuth';

interface StudentInfo {
  name: string;
  studentNumber: string | null;
  gradeLevel: string | null;
  section: string | null;
  enrollmentDate: string | null;
  status: string | null;
}

interface EnrollmentInfo {
  schoolYear: string | null;
  semester: string | null;
  isEnrolled: boolean;
}

interface ClassInfo {
  id: string;
  className: string;
  classCode: string | null;
  gradeLevel: string | null;
  section: string | null;
  semester: string | null;
  schoolYear: string | null;
  room: string | null;
  schedule: string | null;
  isActive: boolean | null;
  teacher: string;
}

interface EnrollmentData {
  student: StudentInfo;
  enrollment: EnrollmentInfo;
  classes: ClassInfo[];
}

function InfoCard({
  icon: Icon,
  label,
  value,
}: {
  icon: React.ElementType;
  label: string;
  value: string | null | undefined;
}) {
  return (
    <div className="flex items-start gap-3 p-4 bg-gray-50 rounded-xl border border-gray-200">
      <div className="flex-shrink-0 w-9 h-9 rounded-lg bg-red-100 flex items-center justify-center">
        <Icon className="w-4 h-4 text-red-700" />
      </div>
      <div>
        <p className="text-xs font-medium text-gray-500 uppercase tracking-wide">
          {label}
        </p>
        <p className="text-sm font-semibold text-gray-900 mt-0.5">
          {value || '—'}
        </p>
      </div>
    </div>
  );
}

export default function EnrollmentPage() {
  const { student, isLoading } = useStudentAuth();
  const { showAlert } = useAlert();
  const [enrollmentData, setEnrollmentData] = useState<EnrollmentData | null>(
    null
  );
  const [dataLoading, setDataLoading] = useState(false);

  const displayName = useMemo(() => {
    if (!student) return 'Student';
    if (student.first_name && student.last_name) {
      return `${student.first_name} ${student.last_name}`;
    }
    return student.email?.split('@')[0] || 'Student';
  }, [student]);

  const fetchEnrollmentData = useCallback(async () => {
    if (!student) return;

    setDataLoading(true);
    try {
      const response = await fetch(
        `/api/student/enrollment?studentId=${student.id}`
      );
      const payload = await response.json().catch(() => ({}));

      if (response.ok && payload?.success && payload?.data) {
        setEnrollmentData(payload.data);
      }
    } catch (error) {
      console.error('Enrollment fetch error:', error);
    } finally {
      setDataLoading(false);
    }
  }, [student]);

  useEffect(() => {
    if (student) {
      fetchEnrollmentData();
    }
  }, [student, fetchEnrollmentData]);

  const info = enrollmentData?.student;
  const enrollment = enrollmentData?.enrollment;
  const classes = enrollmentData?.classes || [];

  const generateCertificationPDF = useCallback(async () => {
    if (!student) {
      showAlert({
        message: 'Please log in to download your certification.',
        type: 'warning',
      });
      return;
    }

    if (!enrollment?.isEnrolled || classes.length === 0) {
      showAlert({
        message: 'No enrollment data available to generate certificate.',
        type: 'warning',
      });
      return;
    }

    try {
      const doc = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4',
      });

      // School header
      doc.setFontSize(14);
      doc.setFont('helvetica', 'bold');
      doc.text('STO. NIÑO DE PRAGA ACADEMY', 105, 20, { align: 'center' });
      doc.setFontSize(10);
      doc.setFont('helvetica', 'normal');
      doc.text('OF LA PAZ HOMES II, INC.', 105, 26, { align: 'center' });
      doc.text('La Paz Homes II/Karlaville Parkhomes, Trece', 105, 30, {
        align: 'center',
      });

      // Title
      doc.setFontSize(16);
      doc.setFont('helvetica', 'bold');
      doc.text('CERTIFICATION OF ENROLLMENT', 105, 45, { align: 'center' });

      // Student information
      const studentName = info?.name || displayName;
      const gradeLevel = info?.gradeLevel || student.grade_level || 'N/A';
      const academicYear = enrollment?.schoolYear || '2024-2025';
      const semester = enrollment?.semester || '';

      doc.setFontSize(12);
      doc.setFont('helvetica', 'normal');
      doc.text(
        `This is to certify that ${studentName.toUpperCase()}`,
        105,
        65,
        { align: 'center' }
      );
      doc.text(
        `is officially enrolled as a student of Grade ${gradeLevel}`,
        105,
        72,
        { align: 'center' }
      );
      doc.text(
        `for the ${semester} of Academic Year ${academicYear}.`,
        105,
        79,
        { align: 'center' }
      );

      // Subjects table
      if (classes.length > 0) {
        let yPos = 95;
        doc.setFontSize(11);
        doc.setFont('helvetica', 'bold');
        doc.text('Enrolled Subjects:', 20, yPos);

        yPos += 8;
        doc.setFontSize(10);
        doc.text('SUBJECT', 25, yPos);
        doc.text('TEACHER', 120, yPos);

        yPos += 6;
        doc.setFont('helvetica', 'normal');
        doc.setFontSize(9);

        classes.forEach((cls) => {
          if (yPos > 250) {
            doc.addPage();
            yPos = 20;
          }
          doc.text(cls.className, 25, yPos);
          doc.text(cls.teacher, 120, yPos);
          yPos += 6;
        });
      }

      // Certification text
      const finalY = classes.length > 0 ? 160 : 100;
      doc.setFontSize(10);
      doc.setFont('helvetica', 'italic');
      doc.text(
        'This certification is issued upon the request of the student',
        105,
        finalY,
        { align: 'center' }
      );
      doc.text('for whatever legal purpose it may serve.', 105, finalY + 6, {
        align: 'center',
      });

      // Date
      const currentDate = new Date().toLocaleDateString('en-US', {
        day: 'numeric',
        month: 'long',
        year: 'numeric',
      });
      doc.setFont('helvetica', 'normal');
      doc.text(
        `Issued this ${currentDate} at SNDPA-LPH, Trece Martires City.`,
        105,
        finalY + 15,
        { align: 'center' }
      );

      // Signatures
      const signatureY = finalY + 35;
      doc.text('MRS. CORAZON R. ULEP', 50, signatureY);
      doc.text('School Registrar', 50, signatureY + 5);
      doc.text('COL GILMAR N GALICIA PA(Res) ME', 150, signatureY);
      doc.text('Principal / Administrator', 150, signatureY + 5);

      const fileName = `Enrollment_Certificate_${studentName.replace(/\s+/g, '_')}.pdf`;
      doc.save(fileName);
    } catch (error: any) {
      console.error('Error generating PDF:', error);
      showAlert({
        message: `Failed to generate PDF: ${error?.message || 'Unknown error'}.`,
        type: 'error',
      });
    }
  }, [student, enrollment, classes, info, displayName, showAlert]);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-xl font-bold text-red-800">Loading...</div>
      </div>
    );
  }

  if (!student) return null;

  const isEnrolled = enrollment?.isEnrolled ?? false;

  return (
    <div className="p-6 space-y-6 max-w-5xl mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between gap-4 flex-wrap">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Enrollment</h2>
          <p className="text-sm text-gray-500 mt-0.5">
            Your current enrollment information and subjects
          </p>
        </div>
        <Button
          onClick={generateCertificationPDF}
          disabled={!isEnrolled || dataLoading}
          className="bg-red-800 hover:bg-red-700 text-white disabled:opacity-50"
        >
          <Download className="w-4 h-4 mr-2" />
          Download Certificate (PDF)
        </Button>
      </div>

      {/* Status banner */}
      <div
        className={`flex items-center justify-between p-4 rounded-xl border ${
          isEnrolled
            ? 'bg-green-50 border-green-200'
            : 'bg-amber-50 border-amber-200'
        }`}
      >
        <div className="flex items-center gap-3">
          <GraduationCap
            className={`w-6 h-6 ${isEnrolled ? 'text-green-700' : 'text-amber-600'}`}
          />
          <div>
            <p
              className={`font-semibold ${isEnrolled ? 'text-green-800' : 'text-amber-800'}`}
            >
              {dataLoading
                ? 'Loading enrollment status…'
                : isEnrolled
                  ? 'Currently Enrolled'
                  : 'Not Enrolled'}
            </p>
            <p
              className={`text-sm ${isEnrolled ? 'text-green-600' : 'text-amber-600'}`}
            >
              {isEnrolled
                ? `${enrollment?.semester ?? ''}${enrollment?.semester && enrollment?.schoolYear ? ' · ' : ''}A.Y. ${enrollment?.schoolYear ?? ''}`
                : 'You are not enrolled in any active class at this time.'}
            </p>
          </div>
        </div>
        <Badge
          className={
            isEnrolled
              ? 'bg-green-100 text-green-800 border-green-300'
              : 'bg-amber-100 text-amber-800 border-amber-300'
          }
        >
          {isEnrolled ? 'Active' : 'Inactive'}
        </Badge>
      </div>

      {/* Student info cards */}
      <Card className="bg-white border border-gray-200 shadow-sm">
        <CardHeader className="pb-3">
          <CardTitle className="text-base flex items-center gap-2">
            <User2 className="w-4 h-4 text-red-700" />
            Student Information
          </CardTitle>
          <CardDescription>Your personal and academic details</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
            <InfoCard
              icon={User2}
              label="Full Name"
              value={info?.name || displayName}
            />
            <InfoCard
              icon={Hash}
              label="Student Number"
              value={info?.studentNumber}
            />
            <InfoCard
              icon={GraduationCap}
              label="Grade Level"
              value={
                info?.gradeLevel
                  ? `Grade ${info.gradeLevel}`
                  : student.grade_level
                    ? `Grade ${student.grade_level}`
                    : null
              }
            />
            <InfoCard icon={Layers} label="Section" value={info?.section} />
            <InfoCard
              icon={Calendar}
              label="Academic Year"
              value={enrollment?.schoolYear}
            />
            <InfoCard
              icon={CalendarDays}
              label="Semester"
              value={enrollment?.semester}
            />
          </div>
        </CardContent>
      </Card>

      {/* Classes / Subjects */}
      <Card className="bg-white border border-gray-200 shadow-sm">
        <CardHeader className="pb-3">
          <CardTitle className="text-base flex items-center gap-2">
            <BookOpen className="w-4 h-4 text-red-700" />
            Enrolled Classes
            {classes.length > 0 && (
              <Badge variant="secondary" className="ml-auto text-xs">
                {classes.length} {classes.length === 1 ? 'class' : 'classes'}
              </Badge>
            )}
          </CardTitle>
          <CardDescription>Your subjects and assigned teachers</CardDescription>
        </CardHeader>
        <CardContent>
          {dataLoading ? (
            <div className="space-y-3">
              {[1, 2, 3].map((i) => (
                <div
                  key={i}
                  className="h-20 bg-gray-100 rounded-xl animate-pulse"
                />
              ))}
            </div>
          ) : classes.length === 0 ? (
            <div className="text-center py-14">
              <GraduationCap
                className="w-14 h-14 text-gray-300 mx-auto mb-3"
                aria-hidden
              />
              <p className="text-gray-500 font-medium">No classes found</p>
              <p className="text-sm text-gray-400 mt-1">
                You are not enrolled in any classes yet.
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              {classes.map((cls) => (
                <div
                  key={cls.id}
                  className={`p-4 rounded-xl border transition-colors hover:bg-gray-50 ${
                    cls.isActive
                      ? 'border-gray-200'
                      : 'border-gray-100 opacity-70'
                  }`}
                >
                  <div className="flex items-start justify-between gap-2 mb-2">
                    <h5 className="font-semibold text-gray-900 text-sm leading-snug">
                      {cls.className}
                    </h5>
                    {cls.classCode && (
                      <span className="text-xs font-mono bg-gray-100 text-gray-600 px-2 py-0.5 rounded-md flex-shrink-0">
                        {cls.classCode}
                      </span>
                    )}
                  </div>
                  <div className="space-y-1 text-xs text-gray-600">
                    <div className="flex items-center gap-1.5">
                      <User2 className="w-3.5 h-3.5 text-gray-400" />
                      <span>{cls.teacher}</span>
                    </div>
                    {cls.room && (
                      <div className="flex items-center gap-1.5">
                        <Building2 className="w-3.5 h-3.5 text-gray-400" />
                        <span>Room {cls.room}</span>
                      </div>
                    )}
                    {cls.schedule && (
                      <div className="flex items-center gap-1.5">
                        <CalendarDays className="w-3.5 h-3.5 text-gray-400" />
                        <span>{cls.schedule}</span>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
